section.programlisting:
import java.io.FileInputStream;
import java.security.cert.CertificateFactory;
import java.security.cert.X509Certificate;
import java.util.Date;
import java.util.List;

import org.bouncycastle.asn1.ASN1ObjectIdentifier;
import org.bouncycastle.asn1.x509.AuthorityInformationAccess;
import org.bouncycastle.asn1.x509.BasicConstraints;
import org.bouncycastle.asn1.x509.CRLDistPoint;
import org.bouncycastle.asn1.x509.DistributionPoint;
import org.bouncycastle.asn1.x509.Extension;
import org.bouncycastle.asn1.x509.GeneralName;
import org.bouncycastle.asn1.x509.KeyUsage;
import org.bouncycastle.cert.X509CertificateHolder;
import org.bouncycastle.cert.jcajce.JcaX509CertificateHolder;

public class CertificateInspector {

    /**
     * Load a certificate from a DER or PEM file and inspect its fields.
     */
    public static void inspectCertificate(String filePath) throws Exception {
        // Load the certificate using JCA
        CertificateFactory cf = CertificateFactory.getInstance("X.509");
        X509Certificate javaCert;
        try (FileInputStream fis = new FileInputStream(filePath)) {
            javaCert = (X509Certificate) cf.generateCertificate(fis);
        }

        // Wrap in BouncyCastle holder for extension access
        X509CertificateHolder holder = new JcaX509CertificateHolder(javaCert);

        // --- Basic fields ---
        String subject = javaCert.getSubjectX500Principal().getName();      
        String issuer = javaCert.getIssuerX500Principal().getName();
        String serial = javaCert.getSerialNumber().toString(16);            
        int version = javaCert.getVersion();
        Date notBefore = javaCert.getNotBefore();
        Date notAfter = javaCert.getNotAfter();
        String sigAlg = javaCert.getSigAlgName();
        String pubKeyAlg = javaCert.getPublicKey().getAlgorithm();
        int keySize = getKeySize(javaCert);

        // --- KeyUsage ---
        boolean[] keyUsageBits = javaCert.getKeyUsage();                    
        if (keyUsageBits != null) {
            boolean digitalSignature = keyUsageBits[0];
            boolean nonRepudiation = keyUsageBits[1];
            boolean keyEncipherment = keyUsageBits[2];
            boolean keyCertSign = keyUsageBits[5];
        }

        // --- BasicConstraints ---
        Extension bcExt = holder.getExtension(Extension.basicConstraints);
        if (bcExt != null) {
            BasicConstraints bc = BasicConstraints.getInstance(
                    bcExt.getParsedValue());
            boolean isCA = bc.isCA();
            int pathLen = bc.getPathLenConstraint() != null
                    ? bc.getPathLenConstraint().intValue() : -1;
        }

        // --- ExtendedKeyUsage ---
        List<String> ekuOids = javaCert.getExtendedKeyUsage();              
        if (ekuOids != null) {
            for (String oid : ekuOids) {
                // Map OID to human-readable name
                String name = mapEkuOid(oid);
            }
        }

        // --- AuthorityInfoAccess (OCSP + CA Issuers) ---
        Extension aiaExt = holder.getExtension(Extension.authorityInfoAccess);
        if (aiaExt != null) {
            AuthorityInformationAccess aia = AuthorityInformationAccess
                    .getInstance(aiaExt.getParsedValue());

            // OCSP responder URLs
            var ocspAccessDescriptions = aia.getAccessDescriptions();
            for (var ad : ocspAccessDescriptions) {
                if (ad.getAccessMethod().equals(
                        new ASN1ObjectIdentifier("1.3.6.1.5.5.7.48.1"))) {
                    String ocspUrl = ad.getAccessLocation()
                            .getName().toString();                          
                }
            }
        }

        // --- CRL Distribution Points ---
        Extension crlExt = holder.getExtension(Extension.cRLDistributionPoints);
        if (crlExt != null) {
            CRLDistPoint crlDistPoint = CRLDistPoint.getInstance(
                    crlExt.getParsedValue());
            for (DistributionPoint dp : crlDistPoint.getDistributionPoints()) {
                // Extract URL from the distribution point
                var dpName = dp.getDistributionPoint();
                if (dpName != null) {
                    var names = org.bouncycastle.asn1.x509.GeneralNames
                            .getInstance(dpName.getName());
                    for (GeneralName name : names.getNames()) {
                        if (name.getTagNo() == GeneralName.uniformResourceIdentifier) {
                            String crlUrl = name.getName().toString();
                        }
                    }
                }
            }
        }
    }

    private static int getKeySize(X509Certificate cert) {
        String algorithm = cert.getPublicKey().getAlgorithm();
        if ("RSA".equals(algorithm)) {
            var rsaKey = (java.security.interfaces.RSAPublicKey) cert.getPublicKey();
            return rsaKey.getModulus().bitLength();
        } else if ("EC".equals(algorithm)) {
            var ecKey = (java.security.interfaces.ECPublicKey) cert.getPublicKey();
            return ecKey.getParams().getOrder().bitLength();
        }
        return -1;
    }

    private static String mapEkuOid(String oid) {
        return switch (oid) {
            case "1.3.6.1.5.5.7.3.4" -> "emailProtection";
            case "1.3.6.1.4.1.311.10.3.12" -> "documentSigning (Microsoft)";
            case "1.2.840.113583.1.1.5" -> "adobeAuthenticDocumentsTrust";
            case "1.3.6.1.5.5.7.3.1" -> "serverAuth (TLS)";
            case "1.3.6.1.5.5.7.3.9" -> "OCSPSigning";
            default -> "unknown (" + oid + ")";
        };
    }
}

import java.security.cert.X509Certificate;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Collection;
import java.util.List;

import org.bouncycastle.asn1.x509.AuthorityKeyIdentifier;
import org.bouncycastle.asn1.x509.Extension;
import org.bouncycastle.asn1.x509.SubjectKeyIdentifier;
import org.bouncycastle.cert.X509CertificateHolder;
import org.bouncycastle.cert.jcajce.JcaX509CertificateHolder;

/**
 * Build a certificate chain from an unordered collection of certificates.
 * Matches AuthorityKeyIdentifier -> SubjectKeyIdentifier.
 */
public class ChainBuilder {

    public static List<X509Certificate> buildChain(
            X509Certificate endEntity,
            Collection<X509Certificate> candidates) throws Exception {

        List<X509Certificate> chain = new ArrayList<>();
        chain.add(endEntity);

        X509Certificate current = endEntity;
        int maxDepth = 10; // prevent infinite loops from malformed chains

        for (int i = 0; i < maxDepth; i++) {
            // Self-signed? We've reached a root.
            if (current.getSubjectX500Principal()
                    .equals(current.getIssuerX500Principal())) {
                break;
            }

            byte[] akiBytes = getAuthorityKeyIdentifier(current);
            if (akiBytes == null) {
                break; // no AKI -- cannot chain further
            }

            X509Certificate issuer = findBySki(candidates, akiBytes);
            if (issuer == null) {
                break; // issuer not in our candidate set
            }

            chain.add(issuer);
            current = issuer;
        }

        return chain;
    }

    private static byte[] getAuthorityKeyIdentifier(
            X509Certificate cert) throws Exception {

        X509CertificateHolder holder = new JcaX509CertificateHolder(cert);
        Extension akiExt = holder.getExtension(
                Extension.authorityKeyIdentifier);
        if (akiExt == null) {
            return null;
        }
        AuthorityKeyIdentifier aki =
                AuthorityKeyIdentifier.getInstance(akiExt.getParsedValue());
        return aki.getKeyIdentifier();
    }

    private static X509Certificate findBySki(
            Collection<X509Certificate> certs,
            byte[] targetSki) throws Exception {

        for (X509Certificate candidate : certs) {
            X509CertificateHolder holder =
                    new JcaX509CertificateHolder(candidate);
            Extension skiExt = holder.getExtension(
                    Extension.subjectKeyIdentifier);
            if (skiExt == null) {
                continue;
            }
            SubjectKeyIdentifier ski =
                    SubjectKeyIdentifier.getInstance(skiExt.getParsedValue());
            if (Arrays.equals(ski.getKeyIdentifier(), targetSki)) {
                return candidate;
            }
        }
        return null;
    }
}

import java.security.cert.CertPathValidator;
import java.security.cert.CertificateFactory;
import java.security.cert.CertPath;
import java.security.cert.PKIXParameters;
import java.security.cert.PKIXCertPathValidatorResult;
import java.security.cert.TrustAnchor;
import java.security.cert.X509Certificate;
import java.util.Collections;
import java.util.List;

/**
 * Validate a certificate chain using the JCA PKIX path validator.
 * This performs the full RFC 5280 section 6 algorithm.
 */
public class PathValidationExample {

    public static PKIXCertPathValidatorResult validateChain(
            List<X509Certificate> chain,
            X509Certificate trustAnchor) throws Exception {

        // The chain list should NOT include the trust anchor
        CertificateFactory cf = CertificateFactory.getInstance("X.509");
        CertPath certPath = cf.generateCertPath(chain);

        TrustAnchor anchor = new TrustAnchor(trustAnchor, null);
        PKIXParameters params = new PKIXParameters(
                Collections.singleton(anchor));

        // Disable revocation checking here -- we handle it separately
        params.setRevocationEnabled(false);

        CertPathValidator validator =
                CertPathValidator.getInstance("PKIX");

        return (PKIXCertPathValidatorResult)
                validator.validate(certPath, params);
    }
}

CRLDistributionPoints ::= SEQUENCE SIZE (1..MAX) OF DistributionPoint

DistributionPoint ::= SEQUENCE {
    distributionPoint  [0] DistributionPointName OPTIONAL,
    reasons            [1] ReasonFlags OPTIONAL,
    cRLIssuer          [2] GeneralNames OPTIONAL
}

OCSPRequest ::= SEQUENCE {
    tbsRequest     TBSRequest,
    optionalSignature [0] EXPLICIT Signature OPTIONAL
}

TBSRequest ::= SEQUENCE {
    version        [0] EXPLICIT Version DEFAULT v1,
    requestorName  [1] EXPLICIT GeneralName OPTIONAL,
    requestList    SEQUENCE OF Request,
    requestExtensions [2] EXPLICIT Extensions OPTIONAL
}

Request ::= SEQUENCE {
    reqCert        CertID,
    singleRequestExtensions [0] EXPLICIT Extensions OPTIONAL
}

CertID ::= SEQUENCE {
    hashAlgorithm  AlgorithmIdentifier,
    issuerNameHash OCTET STRING,
    issuerKeyHash  OCTET STRING,
    serialNumber   CertificateSerialNumber
}

import java.io.InputStream;
import java.io.OutputStream;
import java.math.BigInteger;
import java.net.HttpURLConnection;
import java.net.URI;
import java.security.cert.X509Certificate;

import org.bouncycastle.asn1.DEROctetString;
import org.bouncycastle.asn1.ocsp.OCSPObjectIdentifiers;
import org.bouncycastle.asn1.x509.Extension;
import org.bouncycastle.asn1.x509.Extensions;
import org.bouncycastle.cert.jcajce.JcaX509CertificateHolder;
import org.bouncycastle.cert.ocsp.BasicOCSPResp;
import org.bouncycastle.cert.ocsp.CertificateID;
import org.bouncycastle.cert.ocsp.OCSPReq;
import org.bouncycastle.cert.ocsp.OCSPReqBuilder;
import org.bouncycastle.cert.ocsp.OCSPResp;
import org.bouncycastle.cert.ocsp.SingleResp;
import org.bouncycastle.operator.jcajce.JcaDigestCalculatorProviderBuilder;

/**
 * Send an OCSP request and check the response.
 * Demonstrates the full OCSP round-trip with BouncyCastle.
 */
public class OcspCheckExample {

    public static SingleResp checkOcsp(
            X509Certificate cert,
            X509Certificate issuer,
            String ocspUrl) throws Exception {

        // Build the CertificateID that identifies the cert to check
        CertificateID certId = new CertificateID(
                new JcaDigestCalculatorProviderBuilder()
                        .build()
                        .get(CertificateID.HASH_SHA1),
                new JcaX509CertificateHolder(issuer),
                cert.getSerialNumber());

        // Build the OCSP request
        OCSPReqBuilder reqBuilder = new OCSPReqBuilder();
        reqBuilder.addRequest(certId);

        // Add a nonce (optional -- many responders ignore it)
        BigInteger nonce = BigInteger.valueOf(System.currentTimeMillis());
        Extension nonceExt = new Extension(
                OCSPObjectIdentifiers.id_pkix_ocsp_nonce,
                false,
                new DEROctetString(nonce.toByteArray()));
        reqBuilder.setRequestExtensions(
                new Extensions(new Extension[]{ nonceExt }));

        OCSPReq ocspReq = reqBuilder.build();

        // Send the request via HTTP POST
        URI uri = new URI(ocspUrl);
        HttpURLConnection conn =
                (HttpURLConnection) uri.toURL().openConnection();
        conn.setRequestMethod("POST");
        conn.setRequestProperty("Content-Type",
                "application/ocsp-request");
        conn.setDoOutput(true);

        try (OutputStream os = conn.getOutputStream()) {
            os.write(ocspReq.getEncoded());
        }

        // Parse the response
        OCSPResp ocspResp;
        try (InputStream is = conn.getInputStream()) {
            ocspResp = new OCSPResp(is);
        }

        if (ocspResp.getStatus() != OCSPResp.SUCCESSFUL) {
            throw new RuntimeException(
                    "OCSP response status: " + ocspResp.getStatus());
        }

        BasicOCSPResp basicResp =
                (BasicOCSPResp) ocspResp.getResponseObject();

        // Find the response for our certificate
        for (SingleResp singleResp : basicResp.getResponses()) {
            if (singleResp.getCertID().equals(certId)) {
                return singleResp;
            }
        }

        return null; // no matching response found
    }
}

import java.io.FileInputStream;
import java.security.KeyStore;
import java.security.cert.X509Certificate;
import java.util.Enumeration;

/**
 * List all trusted root certificates in the Java cacerts store.
 */
public class CacertsExample {

    public static void listTrustedRoots() throws Exception {
        String cacertsPath = System.getProperty("java.home")
                + "/lib/security/cacerts";

        KeyStore ks = KeyStore.getInstance("PKCS12");
        try (FileInputStream fis = new FileInputStream(cacertsPath)) {
            ks.load(fis, "changeit".toCharArray());
        }

        Enumeration<String> aliases = ks.aliases();
        int count = 0;
        while (aliases.hasMoreElements()) {
            String alias = aliases.nextElement();
            if (ks.isCertificateEntry(alias)) {
                X509Certificate cert = (X509Certificate)
                        ks.getCertificate(alias);
                count++;
                // cert.getSubjectX500Principal().getName()
                // gives the root CA's distinguished name
            }
        }
        // Typical count: 100-150 root certificates
    }
}

import java.io.FileOutputStream;
import java.security.KeyStore;
import java.security.cert.CertificateFactory;
import java.security.cert.X509Certificate;
import java.io.FileInputStream;

/**
 * Create a custom trust store containing only your organization's
 * root CA certificate. Use this for internal PKI validation.
 */
public class CustomTrustStoreExample {

    public static void createCustomTrustStore(
            String rootCertPath,
            String trustStorePath,
            String password) throws Exception {

        CertificateFactory cf = CertificateFactory.getInstance("X.509");
        X509Certificate rootCert;
        try (FileInputStream fis = new FileInputStream(rootCertPath)) {
            rootCert = (X509Certificate) cf.generateCertificate(fis);
        }

        KeyStore trustStore = KeyStore.getInstance("PKCS12");
        trustStore.load(null, null); // initialize empty store
        trustStore.setCertificateEntry("internal-root", rootCert);

        try (FileOutputStream fos =
                new FileOutputStream(trustStorePath)) {
            trustStore.store(fos, password.toCharArray());
        }
    }
}

import java.io.FileInputStream;
import java.security.KeyStore;
import java.security.PrivateKey;
import java.security.cert.Certificate;
import java.security.cert.X509Certificate;
import java.util.Enumeration;

/**
 * Load a PKCS#12 keystore and extract the signing key and chain.
 */
public class Pkcs12LoadExample {

    public static void loadAndInspect(
            String p12Path, String password) throws Exception {

        KeyStore ks = KeyStore.getInstance("PKCS12");
        try (FileInputStream fis = new FileInputStream(p12Path)) {
            ks.load(fis, password.toCharArray());
        }

        // Enumerate all entries
        Enumeration<String> aliases = ks.aliases();
        while (aliases.hasMoreElements()) {
            String alias = aliases.nextElement();

            if (ks.isKeyEntry(alias)) {
                PrivateKey key = (PrivateKey) ks.getKey(
                        alias, password.toCharArray());    
                Certificate[] chain = ks.getCertificateChain(alias);

                // key.getAlgorithm() -> "RSA" or "EC"
                // key.getFormat() -> "PKCS#8"
                // chain[0] is the end-entity certificate
                // chain[chain.length-1] is closest to the root

                X509Certificate signingCert =
                        (X509Certificate) chain[0];
                // signingCert.getSubjectX500Principal() -> signer DN
                // signingCert.getNotAfter() -> expiration date
            }
        }
    }
}

import java.io.FileReader;
import java.security.KeyPair;
import java.security.PrivateKey;
import java.security.cert.X509Certificate;

import org.bouncycastle.cert.X509CertificateHolder;
import org.bouncycastle.cert.jcajce.JcaX509CertificateConverter;
import org.bouncycastle.openssl.PEMDecryptorProvider;
import org.bouncycastle.openssl.PEMEncryptedKeyPair;
import org.bouncycastle.openssl.PEMKeyPair;
import org.bouncycastle.openssl.PEMParser;
import org.bouncycastle.openssl.jcajce.JcaPEMKeyConverter;
import org.bouncycastle.openssl.jcajce.JcePEMDecryptorProviderBuilder;

/**
 * Load certificates and private keys from PEM files using BouncyCastle.
 */
public class PemLoadExample {

    /**
     * Load a private key from a PEM file.
     * Handles both encrypted and unencrypted keys.
     */
    public static PrivateKey loadPrivateKey(
            String pemPath, String password) throws Exception {

        try (PEMParser parser = new PEMParser(new FileReader(pemPath))) {
            Object obj = parser.readObject();

            JcaPEMKeyConverter converter = new JcaPEMKeyConverter()
                    .setProvider("BC");

            if (obj instanceof PEMEncryptedKeyPair) {
                PEMDecryptorProvider decryptor =
                        new JcePEMDecryptorProviderBuilder()
                                .build(password.toCharArray());
                PEMKeyPair decrypted =
                        ((PEMEncryptedKeyPair) obj).decryptKeyPair(decryptor);
                return converter.getKeyPair(decrypted).getPrivate();
            }

            if (obj instanceof PEMKeyPair) {
                return converter.getKeyPair((PEMKeyPair) obj).getPrivate();
            }

            if (obj instanceof org.bouncycastle.asn1.pkcs.PrivateKeyInfo) {
                return converter.getPrivateKey(
                        (org.bouncycastle.asn1.pkcs.PrivateKeyInfo) obj);
            }

            throw new IllegalArgumentException(
                    "Unexpected PEM object: " + obj.getClass().getName());
        }
    }

    /**
     * Load an X.509 certificate from a PEM file.
     */
    public static X509Certificate loadCertificate(
            String pemPath) throws Exception {

        try (PEMParser parser = new PEMParser(new FileReader(pemPath))) {
            Object obj = parser.readObject();

            if (obj instanceof X509CertificateHolder) {
                return new JcaX509CertificateConverter()
                        .setProvider("BC")
                        .getCertificate((X509CertificateHolder) obj);
            }

            throw new IllegalArgumentException(
                    "Not a certificate: " + obj.getClass().getName());
        }
    }
}

PrivateKeyInfo ::= SEQUENCE {
    version                Version,
    privateKeyAlgorithm    AlgorithmIdentifier,
    privateKey             OCTET STRING
}

EncryptedPrivateKeyInfo ::= SEQUENCE {
    encryptionAlgorithm    AlgorithmIdentifier,
    encryptedData          OCTET STRING
}

import java.security.KeyStore;
import java.security.Provider;
import java.security.Security;

/**
 * Load keys from an HSM via PKCS#11.
 * The private key never leaves the HSM -- signing happens on-device.
 */
public class Pkcs11Example {

    public static KeyStore loadFromHsm(
            String pkcs11ConfigPath, String pin) throws Exception {

        // Configure the SunPKCS11 provider
        Provider p = Security.getProvider("SunPKCS11");
        p = p.configure(pkcs11ConfigPath);      
        Security.addProvider(p);

        // Load the "keystore" -- this actually enumerates
        // objects on the HSM token
        KeyStore ks = KeyStore.getInstance("PKCS11", p);
        ks.load(null, pin.toCharArray());        

        return ks;
        // ks.getKey() returns a key handle, not the actual key bytes
        // Signing with this key executes on the HSM
    }
}

