section.programlisting:
/**
 * Requests a timestamp from a TSA for the given data.
 * Returns the TimeStampToken that can be embedded as an unsigned CMS attribute.
 */
public TimeStampToken requestTimestamp(byte[] dataToTimestamp, String tsaUrl)
        throws Exception {

    // 1. Hash the data
    MessageDigest digest = MessageDigest.getInstance("SHA-256");
    byte[] hash = digest.digest(dataToTimestamp);

    // 2. Create the timestamp request
    TimeStampRequestGenerator reqGen = new TimeStampRequestGenerator();
    reqGen.setCertReq(true);  // Include TSA's cert in the response
    TimeStampRequest tsReq = reqGen.generate(TSPAlgorithms.SHA256, hash);

    // 3. Send to TSA via HTTP
    byte[] reqBytes = tsReq.getEncoded();
    HttpURLConnection conn = (HttpURLConnection)
            new URL(tsaUrl).openConnection();
    conn.setDoOutput(true);
    conn.setRequestMethod("POST");
    conn.setRequestProperty("Content-Type", "application/timestamp-query");
    conn.setConnectTimeout(10000);
    conn.setReadTimeout(30000);

    try (OutputStream out = conn.getOutputStream()) {
        out.write(reqBytes);
    }

    // 4. Read the response
    byte[] respBytes;
    try (InputStream in = conn.getInputStream()) {
        respBytes = in.readAllBytes();
    }

    // 5. Parse and validate the response
    TimeStampResponse tsResp = new TimeStampResponse(respBytes);
    tsResp.validate(tsReq);  // Verify it matches our request

    if (tsResp.getStatus() != PKIStatus.GRANTED
            && tsResp.getStatus() != PKIStatus.GRANTED_WITH_MODS) {
        throw new TSPException("TSA rejected request: status=" +
                tsResp.getStatus() + ", statusString=" +
                tsResp.getStatusString());
    }

    TimeStampToken tsToken = tsResp.getTimeStampToken();
    log.info("Timestamp obtained: time={}, serial={}, TSA={}",
            tsToken.getTimeStampInfo().getGenTime(),
            tsToken.getTimeStampInfo().getSerialNumber(),
            tsToken.getTimeStampInfo().getTsa());

    return tsToken;
}

/**
 * Probes a TSA server by sending a minimal timestamp request.
 * Returns the response time in milliseconds, or -1 if the probe fails.
 */
public long probeTsa(String tsaUrl, int timeoutMs) {
    try {
        // Hash of dummy data — we don't care about the content
        byte[] dummyHash = MessageDigest.getInstance("SHA-256")
                .digest("tsa-probe".getBytes(StandardCharsets.UTF_8));

        TimeStampRequestGenerator gen = new TimeStampRequestGenerator();
        gen.setCertReq(false);  // Minimize response size
        TimeStampRequest req = gen.generate(TSPAlgorithms.SHA256, dummyHash);

        long start = System.nanoTime();

        HttpURLConnection conn = (HttpURLConnection)
                new URL(tsaUrl).openConnection();
        conn.setDoOutput(true);
        conn.setRequestMethod("POST");
        conn.setRequestProperty("Content-Type",
                "application/timestamp-query");
        conn.setConnectTimeout(timeoutMs);
        conn.setReadTimeout(timeoutMs);
        conn.getOutputStream().write(req.getEncoded());

        // Validate Content-Type — some misconfigured servers
        // return an HTML error page with HTTP 200
        String contentType = conn.getContentType();
        if (contentType == null
                || !contentType.contains("timestamp-reply")) {
            log.warn("TSA {} returned unexpected Content-Type: {}",
                    tsaUrl, contentType);
            return -1;
        }

        byte[] respBytes = conn.getInputStream().readAllBytes();
        TimeStampResponse resp = new TimeStampResponse(respBytes);

        long elapsed = (System.nanoTime() - start) / 1_000_000;

        if (resp.getStatus() == PKIStatus.GRANTED
                || resp.getStatus() == PKIStatus.GRANTED_WITH_MODS) {
            return elapsed;
        }
        return -1;
    } catch (Exception e) {
        return -1;
    }
}

/**
 * OCSP response cache.
 * Caches responses by certificate serial number, respects nextUpdate.
 */
private final Map<BigInteger, CachedOcspResponse> ocspCache
        = new ConcurrentHashMap<>();

public byte[] getOcspResponse(X509Certificate cert,
        X509Certificate issuer) throws Exception {
    BigInteger serial = cert.getSerialNumber();
    CachedOcspResponse cached = ocspCache.get(serial);

    if (cached != null && cached.isValid()) {
        log.debug("OCSP cache hit for serial={}", serial);
        return cached.responseBytes();
    }

    // Cache miss or expired — fetch fresh response
    byte[] respBytes = fetchOCSPResponse(cert, issuer);
    if (respBytes != null) {
        OCSPResp ocspResp = new OCSPResp(respBytes);
        BasicOCSPResp basic = (BasicOCSPResp)
                ocspResp.getResponseObject();
        Date nextUpdate = basic.getResponses()[0].getNextUpdate();

        ocspCache.put(serial,
                new CachedOcspResponse(respBytes, nextUpdate));
        log.debug("OCSP cached for serial={}, valid until {}",
                serial, nextUpdate);
    }
    return respBytes;
}

/**
 * CRL cache — caches full CRLs by distribution point URL.
 * CRLs can be large (hundreds of KB), but they change infrequently.
 */
private final Map<String, CachedCrl> crlCache
        = new ConcurrentHashMap<>();

public byte[] getCrl(String crlUrl) throws Exception {
    CachedCrl cached = crlCache.get(crlUrl);

    if (cached != null && cached.nextUpdate().after(new Date())) {
        log.debug("CRL cache hit for {}", crlUrl);
        return cached.crlBytes();
    }

    byte[] crlBytes = downloadCrl(crlUrl);
    CertificateFactory cf = CertificateFactory.getInstance("X.509");
    X509CRL crl = (X509CRL) cf.generateCRL(
            new ByteArrayInputStream(crlBytes));

    crlCache.put(crlUrl,
            new CachedCrl(crlBytes, crl.getNextUpdate()));
    log.debug("CRL cached for {}, valid until {}",
            crlUrl, crl.getNextUpdate());

    return crlBytes;
}

/**
 * Adds a DSS (Document Security Store) dictionary to the PDF,
 * embedding certificates, OCSP responses, and CRLs for all signatures.
 */
public void addDSS(PDDocument doc, List<ValidationData> validationData)
        throws IOException {

    COSDictionary dssDictionary = new COSDictionary();
    COSArray certsArray = new COSArray();
    COSArray ocspsArray = new COSArray();
    COSArray crlsArray = new COSArray();

    for (ValidationData vd : validationData) {
        // Embed certificates
        for (byte[] certBytes : vd.getCertificateChain()) {
            PDStream certStream = new PDStream(doc);
            try (OutputStream os = certStream.createOutputStream()) {
                os.write(certBytes);
            }
            certsArray.add(certStream.getCOSObject());
        }

        // Embed OCSP responses
        for (byte[] ocspBytes : vd.getOcspResponses()) {
            PDStream ocspStream = new PDStream(doc);
            try (OutputStream os = ocspStream.createOutputStream()) {
                os.write(ocspBytes);
            }
            ocspsArray.add(ocspStream.getCOSObject());
        }

        // Embed CRLs
        for (byte[] crlBytes : vd.getCrls()) {
            PDStream crlStream = new PDStream(doc);
            try (OutputStream os = crlStream.createOutputStream()) {
                os.write(crlBytes);
            }
            crlsArray.add(crlStream.getCOSObject());
        }
    }

    if (certsArray.size() > 0) dssDictionary.setItem(COSName.getPDFName("Certs"), certsArray);
    if (ocspsArray.size() > 0) dssDictionary.setItem(COSName.getPDFName("OCSPs"), ocspsArray);
    if (crlsArray.size() > 0) dssDictionary.setItem(COSName.getPDFName("CRLs"), crlsArray);

    // Add DSS to document catalog
    doc.getDocumentCatalog().getCOSObject()
            .setItem(COSName.getPDFName("DSS"), dssDictionary);
}

/**
 * Fetches an OCSP response for the given certificate.
 * Returns the DER-encoded OCSP response bytes.
 */
public byte[] fetchOCSPResponse(X509Certificate cert,
        X509Certificate issuer) throws Exception {

    // 1. Find the OCSP responder URL from the certificate's AIA extension
    String ocspUrl = extractOcspUrl(cert);
    if (ocspUrl == null) {
        log.warn("No OCSP URL in certificate AIA for: {}",
                cert.getSubjectX500Principal());
        return null;
    }

    // 2. Build the OCSP request
    CertificateID certId = new CertificateID(
            new JcaDigestCalculatorProviderBuilder().build()
                    .get(CertificateID.HASH_SHA1),
            new JcaX509CertificateHolder(issuer),
            cert.getSerialNumber());

    OCSPReqBuilder reqBuilder = new OCSPReqBuilder();
    reqBuilder.addRequest(certId);
    OCSPReq ocspReq = reqBuilder.build();

    // 3. Send via HTTP
    HttpURLConnection conn = (HttpURLConnection)
            new URL(ocspUrl).openConnection();
    conn.setDoOutput(true);
    conn.setRequestMethod("POST");
    conn.setRequestProperty("Content-Type", "application/ocsp-request");
    conn.getOutputStream().write(ocspReq.getEncoded());

    byte[] respBytes = conn.getInputStream().readAllBytes();

    // 4. Validate the response
    OCSPResp ocspResp = new OCSPResp(respBytes);
    if (ocspResp.getStatus() != OCSPResp.SUCCESSFUL) {
        log.error("OCSP response status: {}", ocspResp.getStatus());
        return null;
    }

    BasicOCSPResp basicResp = (BasicOCSPResp) ocspResp.getResponseObject();
    SingleResp singleResp = basicResp.getResponses()[0];

    if (singleResp.getCertStatus() == CertificateStatus.GOOD) {
        log.info("OCSP: certificate is GOOD (produced: {})",
                basicResp.getProducedAt());
        return respBytes;
    } else {
        log.error("OCSP: certificate status is NOT GOOD: {}",
                singleResp.getCertStatus());
        return null;  // Certificate is revoked or unknown
    }
}

/**
 * Downloads a CRL from the certificate's CRL Distribution Point.
 * Returns the DER-encoded CRL bytes.
 */
public byte[] fetchCRL(X509Certificate cert) throws Exception {
    String crlUrl = extractCrlUrl(cert);
    if (crlUrl == null) {
        log.warn("No CRL URL in certificate for: {}",
                cert.getSubjectX500Principal());
        return null;
    }

    HttpURLConnection conn = (HttpURLConnection) new URL(crlUrl).openConnection();
    conn.setConnectTimeout(10000);
    conn.setReadTimeout(30000);

    byte[] crlBytes = conn.getInputStream().readAllBytes();

    // Validate the CRL
    CertificateFactory cf = CertificateFactory.getInstance("X.509");
    X509CRL crl = (X509CRL) cf.generateCRL(new ByteArrayInputStream(crlBytes));

    log.info("CRL downloaded: issuer={}, entries={}, nextUpdate={}",
            crl.getIssuerX500Principal(),
            crl.getRevokedCertificates() != null ?
                    crl.getRevokedCertificates().size() : 0,
            crl.getNextUpdate());

    return crlBytes;
}

-- QCStatements extension (ETSI EN 319 412-5) QCStatements ::= SEQUENCE OF QCStatement
QCStatement ::= SEQUENCE { statementId OBJECT IDENTIFIER, statementInfo ANY DEFINED BY statementId OPTIONAL }
-- Key OIDs: -- id-etsi-qcs-QcCompliance (0.4.0.1862.1.1) = "this is a qualified cert" -- id-etsi-qcs-QcSSCD (0.4.0.1862.1.4) = "key is on a QSCD" -- id-etsi-qcs-QcType (0.4.0.1862.1.6) = type (esign, eseal, web)

/**
 * Determines the eIDAS tier of a PDF signature.
 * This is a simplified illustration - production code should use EU DSS
 * which handles the full complexity of EUTL parsing and chain validation.
 */
public EidasTier determineEidasTier(X509Certificate signerCert,
                                     boolean keyOnQscd) {
    // Check if the certificate is qualified (issued by a QTSP)
    boolean isQualifiedCert = isListedOnEutl(signerCert);

    // Check for QCStatements extension
    boolean hasQcCompliance = hasQcStatement(signerCert,
            "0.4.0.1862.1.1");  // id-etsi-qcs-QcCompliance
    boolean hasQscdStatement = hasQcStatement(signerCert,
            "0.4.0.1862.1.4");  // id-etsi-qcs-QcSSCD

    if (isQualifiedCert && hasQcCompliance && (keyOnQscd || hasQscdStatement)) {
        return EidasTier.QUALIFIED;     // QES - Art. 25(2) applies
    }

    if (meetsArticle26Requirements(signerCert)) {
        return EidasTier.ADVANCED;      // AdES - Art. 25(1) applies
    }

    return EidasTier.BASIC;            // Basic - Art. 25(1) applies
}

private boolean hasQcStatement(X509Certificate cert, String oid) {
    byte[] extValue = cert.getExtensionValue("1.3.6.1.5.5.7.1.3");
    if (extValue == null) {
        return false;
    }
    // Parse QCStatements ASN.1 structure
    ASN1Sequence qcStatements = ASN1Sequence.getInstance(
            ASN1OctetString.getInstance(extValue).getOctets());
    for (ASN1Encodable statement : qcStatements) {
        ASN1Sequence seq = ASN1Sequence.getInstance(statement);
        ASN1ObjectIdentifier statementId =
                ASN1ObjectIdentifier.getInstance(seq.getObjectAt(0));
        if (statementId.getId().equals(oid)) {
            return true;
        }
    }
    return false;
}

import java.io.InputStream;
import java.net.URI;
import java.util.ArrayList;
import java.util.List;

import javax.xml.parsers.DocumentBuilderFactory;

import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;

import lombok.Data;
import lombok.extern.slf4j.Slf4j;

/**
 * Parses the EU List of Trusted Lists (LOTL) to extract
 * pointers to each national Trusted Service Status List.
 */
@Slf4j
public class EutlLotlParser {

    private static final String LOTL_URL =
            "https://ec.europa.eu/tools/lotl/eu-lotl.xml";
    private static final String TSL_NS =
            "http://uri.etsi.org/02231/v2#";

    @Data
    public static class TslPointer {
        private String countryCode;
        private String tslUrl;
    }

    public List<TslPointer> parseLotl() throws Exception {
        log.info("Downloading LOTL from: {}", LOTL_URL);

        DocumentBuilderFactory factory =
                DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);
        // Prevent XXE attacks
        factory.setFeature(
                "http://apache.org/xml/features/"
                + "disallow-doctype-decl", true);

        Document doc;
        try (InputStream in = URI.create(LOTL_URL).toURL()
                .openStream()) {
            doc = factory.newDocumentBuilder().parse(in);
        }

        List<TslPointer> pointers = new ArrayList<>();
        NodeList nodes = doc.getElementsByTagNameNS(
                TSL_NS, "OtherTSLPointer");

        for (int i = 0; i < nodes.getLength(); i++) {
            Element pointer = (Element) nodes.item(i);

            NodeList locations = pointer.getElementsByTagNameNS(
                    TSL_NS, "TSLLocation");
            if (locations.getLength() == 0) {
                continue;
            }
            String url = locations.item(0).getTextContent().trim();

            NodeList territories = pointer.getElementsByTagNameNS(
                    TSL_NS, "SchemeTerritory");
            String country = territories.getLength() > 0
                    ? territories.item(0).getTextContent().trim()
                    : "UNKNOWN";

            TslPointer p = new TslPointer();
            p.setCountryCode(country);
            p.setTslUrl(url);
            pointers.add(p);

            log.debug("Found TSL: country={}, url={}", country, url);
        }

        log.info("Parsed LOTL: {} national TSL pointers",
                pointers.size());
        return pointers;
    }
}

import java.io.ByteArrayInputStream;
import java.io.InputStream;
import java.net.URI;
import java.security.cert.CertificateFactory;
import java.security.cert.X509Certificate;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Base64;
import java.util.List;

import javax.xml.parsers.DocumentBuilderFactory;

import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;

import lombok.Data;
import lombok.extern.slf4j.Slf4j;

/**
 * Parses a national TSL and matches signer certificates
 * against qualified CA services listed in the EUTL.
 */
@Slf4j
public class EutlCertificateMatcher {

    private static final String TSL_NS =
            "http://uri.etsi.org/02231/v2#";

    @Data
    public static class QualifiedCaEntry {
        private String providerName;
        private String status;
        private X509Certificate caCertificate;
    }

    /**
     * Downloads a national TSL and extracts all CA/QC services
     * with "granted" status.
     */
    public List<QualifiedCaEntry> parseNationalTsl(String tslUrl)
            throws Exception {
        log.info("Parsing national TSL: {}", tslUrl);

        DocumentBuilderFactory factory =
                DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);
        factory.setFeature(
                "http://apache.org/xml/features/"
                + "disallow-doctype-decl", true);

        Document doc;
        try (InputStream in = URI.create(tslUrl).toURL()
                .openStream()) {
            doc = factory.newDocumentBuilder().parse(in);
        }

        List<QualifiedCaEntry> entries = new ArrayList<>();
        NodeList services = doc.getElementsByTagNameNS(
                TSL_NS, "TSPService");
        CertificateFactory cf =
                CertificateFactory.getInstance("X.509");

        for (int i = 0; i < services.getLength(); i++) {
            Element svc = (Element) services.item(i);

            // Check service type
            NodeList typeNodes = svc.getElementsByTagNameNS(
                    TSL_NS, "ServiceTypeIdentifier");
            if (typeNodes.getLength() == 0) {
                continue;
            }
            String type = typeNodes.item(0)
                    .getTextContent().trim();
            if (!type.contains("CA/QC")) {
                continue;
            }

            // Check status
            NodeList statusNodes = svc.getElementsByTagNameNS(
                    TSL_NS, "ServiceStatus");
            if (statusNodes.getLength() == 0) {
                continue;
            }
            String status = statusNodes.item(0)
                    .getTextContent().trim();
            if (!status.contains("granted")) {
                continue;
            }

            // Extract CA certificate
            NodeList certNodes = svc.getElementsByTagNameNS(
                    TSL_NS, "X509Certificate");
            if (certNodes.getLength() == 0) {
                continue;
            }
            String b64 = certNodes.item(0).getTextContent()
                    .replaceAll("\\s", "");
            byte[] certBytes = Base64.getDecoder().decode(b64);
            X509Certificate cert = (X509Certificate)
                    cf.generateCertificate(
                        new ByteArrayInputStream(certBytes));

            QualifiedCaEntry entry = new QualifiedCaEntry();
            entry.setStatus(status);
            entry.setCaCertificate(cert);
            entries.add(entry);

            log.info("Found qualified CA: {}",
                    cert.getSubjectX500Principal());
        }

        return entries;
    }

    /**
     * Checks whether the given signer certificate was issued
     * by a CA listed in the EUTL with "granted" status.
     */
    public boolean isIssuedByQualifiedCa(
            X509Certificate signerCert,
            X509Certificate issuerCert,
            List<QualifiedCaEntry> eutlEntries) {
        byte[] issuerEncoded;
        try {
            issuerEncoded = issuerCert.getEncoded();
        } catch (Exception e) {
            log.error("Failed to encode issuer cert", e);
            return false;
        }

        for (QualifiedCaEntry entry : eutlEntries) {
            try {
                byte[] eutlEncoded =
                        entry.getCaCertificate().getEncoded();
                if (Arrays.equals(issuerEncoded, eutlEncoded)) {
                    log.info("Issuer matched EUTL entry: {}",
                            entry.getCaCertificate()
                                .getSubjectX500Principal());
                    return true;
                }
            } catch (Exception e) {
                log.warn("Failed to encode EUTL cert", e);
            }
        }
        return false;
    }
}

import java.io.ByteArrayOutputStream;
import java.security.PrivateKey;
import java.security.cert.X509Certificate;

import org.apache.pdfbox.Loader;
import org.apache.pdfbox.pdmodel.PDDocument;
import org.apache.pdfbox.pdmodel.interactive.digitalsignature.PDSignature;

import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;

/**
 * Creates either a qualified signature or a qualified seal on a
 * PDF document. The cryptographic operation is identical -- the
 * distinction is entirely in the certificate used.
 *
 * Signature: cert has QcType esign (0.4.0.1862.1.6.1),
 *            subject = "CN=Alice Smith"
 * Seal:      cert has QcType eseal (0.4.0.1862.1.6.2),
 *            subject = "O=Acme Corp, C=DE"
 */
@Slf4j
@RequiredArgsConstructor
public class PdfSignOrSealService {

    private final PrivateKey privateKey;
    private final X509Certificate[] certificateChain;

    public byte[] signOrSeal(byte[] pdfBytes, String reason,
            String location) throws Exception {

        PDDocument doc = Loader.loadPDF(pdfBytes);

        PDSignature sig = new PDSignature();
        sig.setFilter(PDSignature.FILTER_ADOBE_PPKLITE);
        sig.setSubFilter(
                PDSignature.SUBFILTER_ETSI_CADES_DETACHED);
        sig.setReason(reason);    
        sig.setLocation(location);

        CmsSignatureCreator signer = new CmsSignatureCreator(
                privateKey, certificateChain);

        doc.addSignature(sig, signer);

        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        doc.saveIncremental(baos);
        doc.close();

        log.info("PDF signed/sealed: cert={}, reason={}",
                certificateChain[0].getSubjectX500Principal(),
                reason);
        return baos.toByteArray();
    }
}

import java.security.cert.X509Certificate;

import org.bouncycastle.asn1.ASN1Encodable;
import org.bouncycastle.asn1.ASN1ObjectIdentifier;
import org.bouncycastle.asn1.ASN1OctetString;
import org.bouncycastle.asn1.ASN1Sequence;

import lombok.extern.slf4j.Slf4j;

/**
 * Determines whether a certificate is for electronic signatures
 * (natural person) or electronic seals (legal person) by
 * examining the QcType statement in QCStatements.
 */
@Slf4j
public class SignatureOrSealDetector {

    private static final String QC_STATEMENTS_OID =
            "1.3.6.1.5.5.7.1.3";
    private static final String QC_TYPE_OID = "0.4.0.1862.1.6";
    private static final String ESIGN_OID = "0.4.0.1862.1.6.1";
    private static final String ESEAL_OID = "0.4.0.1862.1.6.2";

    public enum CertType { SIGNATURE, SEAL, UNKNOWN }

    public CertType detect(X509Certificate cert) {
        byte[] extValue = cert.getExtensionValue(QC_STATEMENTS_OID);
        if (extValue == null) {
            return CertType.UNKNOWN;
        }

        try {
            byte[] octets = ASN1OctetString.getInstance(extValue)
                    .getOctets();
            ASN1Sequence statements =
                    ASN1Sequence.getInstance(octets);

            for (ASN1Encodable statement : statements) {
                ASN1Sequence seq =
                        ASN1Sequence.getInstance(statement);
                String oid = ASN1ObjectIdentifier.getInstance(
                        seq.getObjectAt(0)).getId();

                if (!QC_TYPE_OID.equals(oid) || seq.size() < 2) {
                    continue;
                }

                ASN1Sequence typeSeq = ASN1Sequence.getInstance(
                        seq.getObjectAt(1));
                for (ASN1Encodable entry : typeSeq) {
                    String typeOid = ASN1ObjectIdentifier
                            .getInstance(entry).getId();
                    if (ESIGN_OID.equals(typeOid)) {
                        log.info("Certificate type: SIGNATURE");
                        return CertType.SIGNATURE;
                    }
                    if (ESEAL_OID.equals(typeOid)) {
                        log.info("Certificate type: SEAL");
                        return CertType.SEAL;
                    }
                }
            }
        } catch (Exception e) {
            log.warn("Failed to parse QCStatements", e);
        }
        return CertType.UNKNOWN;
    }
}

/**
 * Authenticates with a CSC-compliant remote signing service.
 * Returns an OAuth 2.0 access token for subsequent API calls.
 */
public String authenticate(String cscBaseUrl, String username,
        String password) throws IOException {

    String loginUrl = cscBaseUrl + "/auth/login";
    String requestBody = """
            {
                "remoteUser": "%s",
                "remoteSecret": "%s"
            }
            """.formatted(username, password);

    HttpURLConnection conn = (HttpURLConnection)
            new URL(loginUrl).openConnection();
    conn.setDoOutput(true);
    conn.setRequestMethod("POST");
    conn.setRequestProperty("Content-Type", "application/json");
    conn.setConnectTimeout(10000);
    conn.setReadTimeout(30000);

    try (OutputStream out = conn.getOutputStream()) {
        out.write(requestBody.getBytes(StandardCharsets.UTF_8));
    }

    if (conn.getResponseCode() != 200) {
        throw new IOException("CSC auth/login failed: HTTP " +
                conn.getResponseCode());
    }

    // Parse JSON response — extract access_token
    String responseJson;
    try (InputStream in = conn.getInputStream()) {
        responseJson = new String(in.readAllBytes(), StandardCharsets.UTF_8);
    }

    // In production, use a proper JSON parser (Jackson, Gson)
    // This is simplified for illustration
    log.info("CSC authentication successful for user: {}", username);
    return extractJsonField(responseJson, "access_token");
}

/**
 * Lists the signing credentials available to the authenticated user.
 * Returns credential IDs that can be used for signing.
 */
public List<CscCredential> listCredentials(String cscBaseUrl,
        String accessToken) throws IOException {

    String url = cscBaseUrl + "/credentials/list";
    String requestBody = """
            {
                "maxResults": 100
            }
            """;

    HttpURLConnection conn = (HttpURLConnection)
            new URL(url).openConnection();
    conn.setDoOutput(true);
    conn.setRequestMethod("POST");
    conn.setRequestProperty("Content-Type", "application/json");
    conn.setRequestProperty("Authorization", "Bearer " + accessToken);

    try (OutputStream out = conn.getOutputStream()) {
        out.write(requestBody.getBytes(StandardCharsets.UTF_8));
    }

    String responseJson;
    try (InputStream in = conn.getInputStream()) {
        responseJson = new String(in.readAllBytes(), StandardCharsets.UTF_8);
    }

    // Response contains:
    // {
    //   "credentialIDs": ["cred-001", "cred-002"],
    //   "credentialInfos": [
    //     {
    //       "credentialID": "cred-001",
    //       "key": { "algo": ["1.2.840.113549.1.1.11"], "len": 2048 },
    //       "cert": { "certificates": ["MIIC...", "MIID..."] },
    //       "SCAL": "2",
    //       "description": "Qualified certificate for John Doe"
    //     }
    //   ]
    // }

    log.info("CSC credentials/list returned credentials for user");
    return parseCscCredentials(responseJson);
}

/**
 * Authorizes a credential for signing (SCAL2).
 * Triggers user authentication (OTP, biometric, etc.).
 * Returns a SAD token valid for a limited time and number of signatures.
 */
public String authorizeCredential(String cscBaseUrl, String accessToken,
        String credentialId, int numSignatures) throws IOException {

    // Step 1: Trigger OTP delivery
    String sendOtpUrl = cscBaseUrl + "/credentials/sendOTP";
    String otpRequestBody = """
            {
                "credentialID": "%s"
            }
            """.formatted(credentialId);

    HttpURLConnection otpConn = (HttpURLConnection)
            new URL(sendOtpUrl).openConnection();
    otpConn.setDoOutput(true);
    otpConn.setRequestMethod("POST");
    otpConn.setRequestProperty("Content-Type", "application/json");
    otpConn.setRequestProperty("Authorization", "Bearer " + accessToken);
    try (OutputStream out = otpConn.getOutputStream()) {
        out.write(otpRequestBody.getBytes(StandardCharsets.UTF_8));
    }

    log.info("OTP sent for credential: {}", credentialId);

    // Step 2: Collect OTP from user (your UI must handle this)
    String otp = collectOtpFromUser();

    // Step 3: Authorize the credential with the OTP
    String authUrl = cscBaseUrl + "/credentials/authorize";
    String authRequestBody = """
            {
                "credentialID": "%s",
                "numSignatures": %d,
                "OTP": "%s"
            }
            """.formatted(credentialId, numSignatures, otp);

    HttpURLConnection authConn = (HttpURLConnection)
            new URL(authUrl).openConnection();
    authConn.setDoOutput(true);
    authConn.setRequestMethod("POST");
    authConn.setRequestProperty("Content-Type", "application/json");
    authConn.setRequestProperty("Authorization", "Bearer " + accessToken);
    try (OutputStream out = authConn.getOutputStream()) {
        out.write(authRequestBody.getBytes(StandardCharsets.UTF_8));
    }

    String responseJson;
    try (InputStream in = authConn.getInputStream()) {
        responseJson = new String(in.readAllBytes(), StandardCharsets.UTF_8);
    }

    // Response: { "SAD": "eyJhbGciOiJSUzI1NiIs..." }
    String sad = extractJsonField(responseJson, "SAD");
    log.info("Credential authorized, SAD obtained for {} signatures",
            numSignatures);
    return sad;
}

/**
 * Signs one or more hashes using a CSC-compliant remote signing service.
 * Returns raw signature values (one per hash).
 */
public List<byte[]> signHashes(String cscBaseUrl, String accessToken,
        String credentialId, String sad,
        List<byte[]> hashes) throws IOException {

    String signUrl = cscBaseUrl + "/signatures/signHash";

    // Convert hashes to Base64 for JSON transport
    List<String> hashesBase64 = new ArrayList<>();
    for (byte[] hash : hashes) {
        hashesBase64.add(Base64.getEncoder().encodeToString(hash));
    }

    // Build JSON array of hashes
    StringBuilder hashArray = new StringBuilder("[");
    for (int i = 0; i < hashesBase64.size(); i++) {
        if (i > 0) hashArray.append(",");
        hashArray.append("\"").append(hashesBase64.get(i)).append("\"");
    }
    hashArray.append("]");

    String requestBody = """
            {
                "credentialID": "%s",
                "SAD": "%s",
                "hashes": %s,
                "hashAlgo": "2.16.840.1.101.3.4.2.1",
                "signAlgo": "1.2.840.113549.1.1.11"
            }
            """.formatted(credentialId, sad, hashArray.toString());

    HttpURLConnection conn = (HttpURLConnection)
            new URL(signUrl).openConnection();
    conn.setDoOutput(true);
    conn.setRequestMethod("POST");
    conn.setRequestProperty("Content-Type", "application/json");
    conn.setRequestProperty("Authorization", "Bearer " + accessToken);

    try (OutputStream out = conn.getOutputStream()) {
        out.write(requestBody.getBytes(StandardCharsets.UTF_8));
    }

    String responseJson;
    try (InputStream in = conn.getInputStream()) {
        responseJson = new String(in.readAllBytes(), StandardCharsets.UTF_8);
    }

    // Response: { "signatures": ["MEUCIQD...", "MEQCIBD..."] }
    List<byte[]> signatures = parseSignatureValues(responseJson);
    log.info("CSC signHash returned {} signature values", signatures.size());
    return signatures;
}

/**
 * Signs a hash using an HSM via PKCS#11.
 * This runs on the remote signing server, NOT on the client.
 */
public byte[] signWithHsm(byte[] hash, String keyAlias,
        char[] keyPin) throws Exception {

    // 1. Load the PKCS#11 provider
    //    (configured once at server startup, not per request)
    Provider pkcs11Provider = Security.getProvider("SunPKCS11");

    // 2. Load the keystore from the HSM
    KeyStore ks = KeyStore.getInstance("PKCS11", pkcs11Provider);
    ks.load(null, keyPin);

    // 3. Retrieve the private key
    PrivateKey privateKey = (PrivateKey) ks.getKey(keyAlias, keyPin);
    if (privateKey == null) {
        throw new IllegalStateException(
                "Key not found in HSM: " + keyAlias);
    }

    // 4. Sign the hash
    //    Note: for RSA, Signature.sign() expects the raw data, not a
    //    pre-computed hash. Use "NONEwithRSA" to sign a raw hash, or
    //    use "SHA256withRSA" and pass the original data.
    Signature sig = Signature.getInstance("SHA256withRSA", pkcs11Provider);
    sig.initSign(privateKey);
    sig.update(hash);
    byte[] signatureValue = sig.sign();

    log.info("HSM signing completed: key={}, sigLen={}",
            keyAlias, signatureValue.length);
    return signatureValue;
}

